24	
25	class Container implements ArrayAccess, ContainerContract
26	{
27	    use ReflectsClosures;
28	
29	    /**
30	     * The current globally available container (if any).
31	     *
32	     * @var static
33	     */
34	    protected static $instance;
35	
36	    /**
37	     * An array of the types that have been resolved.
38	     *
39	     * @var bool[]
40	     */
41	    protected $resolved = [];
42	
43	    /**
44	     * The container's bindings.
45	     *
46	     * @var array[]
47	     */
48	    protected $bindings = [];
49	
50	    /**
51	     * The container's method bindings.
52	     *
53	     * @var \Closure[]
54	     */
55	    protected $methodBindings = [];
56	
57	    /**
58	     * The container's shared instances.
59	     *
60	     * @var object[]
61	     */
62	    protected $instances = [];
63	
64	    /**
65	     * The container's scoped instances.
66	     *
67	     * @var array
68	     */
69	    protected $scopedInstances = [];
70	
71	    /**
72	     * The registered type aliases.
73	     *
74	     * @var string[]
75	     */
76	    protected $aliases = [];
77	
78	    /**
79	     * The registered aliases keyed by the abstract name.
80	     *
81	     * @var array[]
82	     */
83	    protected $abstractAliases = [];
84	
85	    /**
86	     * The extension closures for services.
87	     *
88	     * @var array[]
89	     */
90	    protected $extenders = [];
91	
92	    /**
93	     * All of the registered tags.
94	     *
95	     * @var array[]
96	     */
97	    protected $tags = [];
98	
99	    /**
100	     * The stack of concretions currently being built.
101	     *
102	     * @var array[]
103	     */
104	    protected $buildStack = [];
105	
106	    /**
107	     * The parameter override stack.
108	     *
109	     * @var array[]
110	     */
111	    protected $with = [];
112	
113	    /**
114	     * The contextual binding map.
115	     *
116	     * @var array[]
117	     */
118	    public $contextual = [];
119	
120	    /**
121	     * The contextual attribute handlers.
122	     *
123	     * @var array[]
124	     */
125	    public $contextualAttributes = [];
126	
127	    /**
128	     * Whether an abstract class has already had its attributes checked for bindings.
129	     *
130	     * @var array<class-string, true>
131	     */
132	    protected $checkedForAttributeBindings = [];
133	
134	    /**
135	     * Whether a class has already been checked for Singleton or Scoped attributes.
136	     *
137	     * @var array<class-string, "scoped"|"singleton"|null>
138	     */
139	    protected $checkedForSingletonOrScopedAttributes = [];
140	
141	    /**
142	     * All of the registered rebound callbacks.
143	     *
144	     * @var array[]
145	     */
146	    protected $reboundCallbacks = [];
147	
148	    /**
149	     * All of the global before resolving callbacks.
150	     *
151	     * @var \Closure[]
152	     */
153	    protected $globalBeforeResolvingCallbacks = [];
154	
155	    /**
156	     * All of the global resolving callbacks.
157	     *
158	     * @var \Closure[]
159	     */
160	    protected $globalResolvingCallbacks = [];
161	
162	    /**
163	     * All of the global after resolving callbacks.
164	     *
165	     * @var \Closure[]
166	     */
167	    protected $globalAfterResolvingCallbacks = [];
168	
169	    /**
170	     * All of the before resolving callbacks by class type.
171	     *
172	     * @var array[]
173	     */
174	    protected $beforeResolvingCallbacks = [];
175	
176	    /**
177	     * All of the resolving callbacks by class type.
178	     *
179	     * @var array[]
180	     */
181	    protected $resolvingCallbacks = [];
182	
183	    /**
184	     * All of the after resolving callbacks by class type.
185	     *
186	     * @var array[]
187	     */
188	    protected $afterResolvingCallbacks = [];
189	
190	    /**
191	     * All of the after resolving attribute callbacks by class type.
192	     *
193	     * @var array[]
194	     */
195	    protected $afterResolvingAttributeCallbacks = [];
196	
197	    /**
198	     * The callback used to determine the container's environment.
199	     *
200	     * @var (callable(array<int, string>|string): bool|string)|null
201	     */
202	    protected $environmentResolver = null;
203	
204	    /**
205	     * Define a contextual binding.
206	     *
207	     * @param  array|string  $concrete
208	     * @return \Illuminate\Contracts\Container\ContextualBindingBuilder
209	     */
210	    public function when($concrete)
211	    {
212	        $aliases = [];
213	
214	        foreach (Util::arrayWrap($concrete) as $c) {
215	            $aliases[] = $this->getAlias($c);
216	        }
217	
218	        return new ContextualBindingBuilder($this, $aliases);
219	    }
220	
221	    /**
222	     * Define a contextual binding based on an attribute.
223	     *
224	     * @return void
225	     */
226	    public function whenHasAttribute(string $attribute, Closure $handler)
227	    {
228	        $this->contextualAttributes[$attribute] = $handler;
229	    }
230	
231	    /**
232	     * Determine if the given abstract type has been bound.
233	     *
234	     * @param  string  $abstract
235	     * @return bool
236	     */
237	    public function bound($abstract)
238	    {
239	        return isset($this->bindings[$abstract]) ||
240	               isset($this->instances[$abstract]) ||
241	               $this->isAlias($abstract);
242	    }
243	
244	    /**
245	     * {@inheritdoc}
246	     */
247	    public function has(string $id): bool
248	    {
249	        return $this->bound($id);
250	    }
251	
252	    /**
253	     * Determine if the given abstract type has been resolved.
254	     *
255	     * @param  string  $abstract
256	     * @return bool
257	     */
258	    public function resolved($abstract)
259	    {
260	        if ($this->isAlias($abstract)) {
261	            $abstract = $this->getAlias($abstract);
262	        }
263	
264	        return isset($this->resolved[$abstract]) ||
265	               isset($this->instances[$abstract]);
266	    }
267	
268	    /**
269	     * Determine if a given type is shared.
270	     *
271	     * @param  string  $abstract
272	     * @return bool
273	     */
274	    public function isShared($abstract)
275	    {
276	        if (isset($this->instances[$abstract])) {
277	            return true;
278	        }
279	
280	        if (isset($this->bindings[$abstract]['shared']) && $this->bindings[$abstract]['shared'] === true) {
281	            return true;
282	        }
283	
284	        if (! class_exists($abstract)) {
285	            return false;
286	        }
287	
288	        if (($scopedType = $this->getScopedTyped($abstract)) === null) {
289	            return false;
290	        }
291	
292	        if ($scopedType === 'scoped') {
293	            if (! in_array($abstract, $this->scopedInstances, true)) {
294	                $this->scopedInstances[] = $abstract;
295	            }
296	        }
297	
298	        return true;
299	    }
300	
301	    /**
302	     * Determine if a ReflectionClass has scoping attributes applied.
303	     *
304	     * @param  ReflectionClass<object>|class-string  $reflection
305	     * @return "singleton"|"scoped"|null
306	     */
307	    protected function getScopedTyped(ReflectionClass|string $reflection): ?string
308	    {
309	        $className = $reflection instanceof ReflectionClass
310	            ? $reflection->getName()
311	            : $reflection;
312	
313	        if (array_key_exists($className, $this->checkedForSingletonOrScopedAttributes)) {
314	            return $this->checkedForSingletonOrScopedAttributes[$className];
315	        }
316	
317	        try {
318	            $reflection = $reflection instanceof ReflectionClass
319	                ? $reflection
320	                : new ReflectionClass($reflection);
321	        } catch (ReflectionException) {
322	            return $this->checkedForSingletonOrScopedAttributes[$className] = null;
323	        }
324	
325	        $type = null;
326	
327	        if (! empty($reflection->getAttributes(Singleton::class))) {
328	            $type = 'singleton';
329	        } elseif (! empty($reflection->getAttributes(Scoped::class))) {
330	            $type = 'scoped';
331	        }
332	
333	        return $this->checkedForSingletonOrScopedAttributes[$className] = $type;
334	    }
335	
336	    /**
337	     * Determine if a given string is an alias.
338	     *
339	     * @param  string  $name
340	     * @return bool
341	     */
342	    public function isAlias($name)
343	    {
344	        return isset($this->aliases[$name]);
345	    }
346	
347	    /**
348	     * Register a binding with the container.
349	     *
350	     * @param  \Closure|string  $abstract
351	     * @param  \Closure|string|null  $concrete
352	     * @param  bool  $shared
353	     * @return void
354	     *
355	     * @throws \TypeError
356	     * @throws ReflectionException
357	     */
358	    public function bind($abstract, $concrete = null, $shared = false)
359	    {
360	        if ($abstract instanceof Closure) {
361	            return $this->bindBasedOnClosureReturnTypes(
362	                $abstract, $concrete, $shared
363	            );
364	        }
365	
366	        $this->dropStaleInstances($abstract);
367	
368	        // If no concrete type was given, we will simply set the concrete type to the
369	        // abstract type. After that, the concrete type to be registered as shared
370	        // without being forced to state their classes in both of the parameters.
371	        if (is_null($concrete)) {
372	            $concrete = $abstract;
373	        }
374	
375	        // If the factory is not a Closure, it means it is just a class name which is
376	        // bound into this container to the abstract type and we will just wrap it
377	        // up inside its own Closure to give us more convenience when extending.
378	        if (! $concrete instanceof Closure) {
379	            if (! is_string($concrete)) {
380	                throw new TypeError(self::class.'::bind(): Argument #2 ($concrete) must be of type Closure|string|null');
381	            }
382	
383	            $concrete = $this->getClosure($abstract, $concrete);
384	        }
385	
386	        $this->bindings[$abstract] = ['concrete' => $concrete, 'shared' => $shared];
387	
388	        // If the abstract type was already resolved in this container we'll fire the
389	        // rebound listener so that any objects which have already gotten resolved
390	        // can have their copy of the object updated via the listener callbacks.
391	        if ($this->resolved($abstract)) {
392	            $this->rebound($abstract);
393	        }
394	    }
395	
396	    /**
397	     * Get the Closure to be used when building a type.
398	     *
399	     * @param  string  $abstract
400	     * @param  string  $concrete
401	     * @return \Closure
402	     */
403	    protected function getClosure($abstract, $concrete)
404	    {
405	        return function ($container, $parameters = []) use ($abstract, $concrete) {
406	            if ($abstract == $concrete) {
407	                return $container->build($concrete);
408	            }
409	
410	            return $container->resolve(
411	                $concrete, $parameters, raiseEvents: false
412	            );
413	        };
414	    }
415	
416	    /**
417	     * Determine if the container has a method binding.
418	     *
419	     * @param  string  $method
420	     * @return bool
421	     */
422	    public function hasMethodBinding($method)
423	    {
424	        return isset($this->methodBindings[$method]);
425	    }
426	
427	    /**
428	     * Bind a callback to resolve with Container::call.
429	     *
430	     * @param  array|string  $method
431	     * @param  \Closure  $callback
432	     * @return void
433	     */
434	    public function bindMethod($method, $callback)
435	    {
436	        $this->methodBindings[$this->parseBindMethod($method)] = $callback;
437	    }
438	
439	    /**
440	     * Get the method to be bound in class@method format.
441	     *
442	     * @param  array|string  $method
443	     * @return string
444	     */
445	    protected function parseBindMethod($method)
446	    {
447	        if (is_array($method)) {
448	            return $method[0].'@'.$method[1];
449	        }
450	
451	        return $method;
452	    }
453	
454	    /**
455	     * Get the method binding for the given method.
456	     *
457	     * @param  string  $method
458	     * @param  mixed  $instance
459	     * @return mixed
460	     */
461	    public function callMethodBinding($method, $instance)
462	    {
463	        return call_user_func($this->methodBindings[$method], $instance, $this);
464	    }
465	
466	    /**
467	     * Add a contextual binding to the container.
468	     *
469	     * @param  string  $concrete
470	     * @param  \Closure|string  $abstract
471	     * @param  \Closure|string  $implementation
472	     * @return void
473	     */
474	    public function addContextualBinding($concrete, $abstract, $implementation)
475	    {
476	        $this->contextual[$concrete][$this->getAlias($abstract)] = $implementation;
477	    }
478	
479	    /**
480	     * Register a binding if it hasn't already been registered.
481	     *
482	     * @param  \Closure|string  $abstract
483	     * @param  \Closure|string|null  $concrete
484	     * @param  bool  $shared
485	     * @return void
486	     */
487	    public function bindIf($abstract, $concrete = null, $shared = false)
488	    {
489	        if (! $this->bound($abstract)) {
490	            $this->bind($abstract, $concrete, $shared);
491	        }
492	    }
493	
494	    /**
495	     * Register a shared binding in the container.
496	     *
497	     * @param  \Closure|string  $abstract
498	     * @param  \Closure|string|null  $concrete
499	     * @return void
500	     */
501	    public function singleton($abstract, $concrete = null)
502	    {
503	        $this->bind($abstract, $concrete, true);
504	    }
505	
506	    /**
507	     * Register a shared binding if it hasn't already been registered.
508	     *
509	     * @param  \Closure|string  $abstract
510	     * @param  \Closure|string|null  $concrete
511	     * @return void
512	     */
513	    public function singletonIf($abstract, $concrete = null)
514	    {
515	        if (! $this->bound($abstract)) {
516	            $this->singleton($abstract, $concrete);
517	        }
518	    }
519	
520	    /**
521	     * Register a scoped binding in the container.
522	     *
523	     * @param  \Closure|string  $abstract
524	     * @param  \Closure|string|null  $concrete
525	     * @return void
526	     */
527	    public function scoped($abstract, $concrete = null)
528	    {
529	        $this->scopedInstances[] = $abstract;
530	
531	        $this->singleton($abstract, $concrete);
532	    }
533	
534	    /**
535	     * Register a scoped binding if it hasn't already been registered.
536	     *
537	     * @param  \Closure|string  $abstract
538	     * @param  \Closure|string|null  $concrete
539	     * @return void
540	     */
541	    public function scopedIf($abstract, $concrete = null)
542	    {
543	        if (! $this->bound($abstract)) {
544	            $this->scoped($abstract, $concrete);
545	        }
546	    }
547	
548	    /**
549	     * Register a binding with the container based on the given Closure's return types.
550	     *
551	     * @param  \Closure|string  $abstract
552	     * @param  \Closure|string|null  $concrete
553	     * @param  bool  $shared
554	     * @return void
555	     */
556	    protected function bindBasedOnClosureReturnTypes($abstract, $concrete = null, $shared = false)
557	    {
558	        $abstracts = $this->closureReturnTypes($abstract);
559	
560	        $concrete = $abstract;
561	
562	        foreach ($abstracts as $abstract) {
563	            $this->bind($abstract, $concrete, $shared);
564	        }
565	    }
566	
567	    /**
568	     * "Extend" an abstract type in the container.
569	     *
570	     * @param  string  $abstract
571	     * @return void
572	     *
573	     * @throws \InvalidArgumentException
574	     */
575	    public function extend($abstract, Closure $closure)
576	    {
577	        $abstract = $this->getAlias($abstract);
578	
579	        if (isset($this->instances[$abstract])) {
580	            $this->instances[$abstract] = $closure($this->instances[$abstract], $this);
581	
582	            $this->rebound($abstract);
583	        } else {
584	            $this->extenders[$abstract][] = $closure;
585	
586	            if ($this->resolved($abstract)) {
587	                $this->rebound($abstract);
588	            }
589	        }
590	    }
591	
592	    /**
593	     * Register an existing instance as shared in the container.
594	     *
595	     * @template TInstance of mixed
596	     *
597	     * @param  string  $abstract
598	     * @param  TInstance  $instance
599	     * @return TInstance
600	     */
601	    public function instance($abstract, $instance)
602	    {
603	        $this->removeAbstractAlias($abstract);
604	
605	        $isBound = $this->bound($abstract);
606	
607	        unset($this->aliases[$abstract]);
608	
609	        // We'll check to determine if this type has been bound before, and if it has
610	        // we will fire the rebound callbacks registered with the container and it
611	        // can be updated with consuming classes that have gotten resolved here.
612	        $this->instances[$abstract] = $instance;
613	
614	        if ($isBound) {
615	            $this->rebound($abstract);
616	        }
617	
618	        return $instance;
619	    }
620	
621	    /**
622	     * Remove an alias from the contextual binding alias cache.
623	     *
624	     * @param  string  $searched
625	     * @return void
626	     */
627	    protected function removeAbstractAlias($searched)
628	    {
629	        if (! isset($this->aliases[$searched])) {
630	            return;
631	        }
632	
633	        foreach ($this->abstractAliases as $abstract => $aliases) {
634	            foreach ($aliases as $index => $alias) {
635	                if ($alias == $searched) {
636	                    unset($this->abstractAliases[$abstract][$index]);
637	                }
638	            }
639	        }
640	    }
641	
642	    /**
643	     * Assign a set of tags to a given binding.
644	     *
645	     * @param  array|string  $abstracts
646	     * @param  mixed  ...$tags
647	     * @return void
648	     */
649	    public function tag($abstracts, $tags)
650	    {
651	        $tags = is_array($tags) ? $tags : array_slice(func_get_args(), 1);
652	
653	        foreach ($tags as $tag) {
654	            if (! isset($this->tags[$tag])) {
655	                $this->tags[$tag] = [];
656	            }
657	
658	            foreach ((array) $abstracts as $abstract) {
659	                $this->tags[$tag][] = $abstract;
660	            }
661	        }
662	    }
663	
664	    /**
665	     * Resolve all of the bindings for a given tag.
666	     *
667	     * @param  string  $tag
668	     * @return iterable
669	     */
670	    public function tagged($tag)
671	    {
672	        if (! isset($this->tags[$tag])) {
673	            return [];
674	        }
675	
676	        return new RewindableGenerator(function () use ($tag) {
677	            foreach ($this->tags[$tag] as $abstract) {
678	                yield $this->make($abstract);
679	            }
680	        }, count($this->tags[$tag]));
681	    }
682	
683	    /**
684	     * Alias a type to a different name.
685	     *
686	     * @param  string  $abstract
687	     * @param  string  $alias
688	     * @return void
689	     *
690	     * @throws \LogicException
691	     */
692	    public function alias($abstract, $alias)
693	    {
694	        if ($alias === $abstract) {
695	            throw new LogicException("[{$abstract}] is aliased to itself.");
696	        }
697	
698	        $this->removeAbstractAlias($alias);
699	
700	        $this->aliases[$alias] = $abstract;
701	
702	        $this->abstractAliases[$abstract][] = $alias;
703	    }
704	
705	    /**
706	     * Bind a new callback to an abstract's rebind event.
707	     *
708	     * @param  string  $abstract
709	     * @return mixed
710	     */
711	    public function rebinding($abstract, Closure $callback)
712	    {
713	        $this->reboundCallbacks[$abstract = $this->getAlias($abstract)][] = $callback;
714	
715	        if ($this->bound($abstract)) {
716	            return $this->make($abstract);
717	        }
718	    }
719	
720	    /**
721	     * Refresh an instance on the given target and method.
722	     *
723	     * @param  string  $abstract
724	     * @param  mixed  $target
725	     * @param  string  $method
726	     * @return mixed
727	     */
728	    public function refresh($abstract, $target, $method)
729	    {
730	        return $this->rebinding($abstract, function ($app, $instance) use ($target, $method) {
731	            $target->{$method}($instance);
732	        });
733	    }
734	
735	    /**
736	     * Fire the "rebound" callbacks for the given abstract type.
737	     *
738	     * @param  string  $abstract
739	     * @return void
740	     */
741	    protected function rebound($abstract)
742	    {
743	        if (! $callbacks = $this->getReboundCallbacks($abstract)) {
744	            return;
745	        }
746	
747	        $instance = $this->make($abstract);
748	
749	        foreach ($callbacks as $callback) {
750	            $callback($this, $instance);
751	        }
752	    }
753	
754	    /**
755	     * Get the rebound callbacks for a given type.
756	     *
757	     * @param  string  $abstract
758	     * @return array
759	     */
760	    protected function getReboundCallbacks($abstract)
761	    {
762	        return $this->reboundCallbacks[$abstract] ?? [];
763	    }
764	
765	    /**
766	     * Wrap the given closure such that its dependencies will be injected when executed.
767	     *
768	     * @return \Closure
769	     */
770	    public function wrap(Closure $callback, array $parameters = [])
771	    {
772	        return fn () => $this->call($callback, $parameters);
773	    }
774	
775	    /**
776	     * Call the given Closure / class@method and inject its dependencies.
777	     *
778	     * @param  callable|string  $callback
779	     * @param  array<string, mixed>  $parameters
780	     * @param  string|null  $defaultMethod
781	     * @return mixed
782	     *
783	     * @throws \InvalidArgumentException
784	     */
785	    public function call($callback, array $parameters = [], $defaultMethod = null)
786	    {
787	        $pushedToBuildStack = false;
788	
789	        if (($className = $this->getClassForCallable($callback)) && ! in_array(
790	            $className,
791	            $this->buildStack,
792	            true
793	        )) {
794	            $this->buildStack[] = $className;
795	
796	            $pushedToBuildStack = true;
797	        }
