46	     * @param  string|null  $defaultMethod
47	     * @return mixed
48	     *
49	     * @throws \InvalidArgumentException
50	     */
51	    protected static function callClass($container, $target, array $parameters = [], $defaultMethod = null)
52	    {
53	        $segments = explode('@', $target);
54	
55	        // We will assume an @ sign is used to delimit the class name from the method
56	        // name. We will split on this @ sign and then build a callable array that
57	        // we can pass right back into the "call" method for dependency binding.
58	        $method = count($segments) === 2
59	            ? $segments[1]
60	            : $defaultMethod;
61	
62	        if (is_null($method)) {
63	            throw new InvalidArgumentException('Method not provided.');
64	        }
65	
66	        return static::call(
67	            $container,
68	            [$container->make($segments[0]), $method],
69	            $parameters
70	        );
71	    }
72	
73	    /**
74	     * Call a method that has been bound to the container.
75	     *
76	     * @param  \Illuminate\Container\Container  $container
77	     * @param  callable  $callback
78	     * @param  mixed  $default
79	     * @return mixed
80	     */
81	    protected static function callBoundMethod($container, $callback, $default)
82	    {
83	        if (! is_array($callback)) {
84	            return Util::unwrapIfClosure($default);
85	        }
86	
87	        // Here we need to turn the array callable into a Class@method string we can use to
88	        // examine the container and see if there are any method bindings for this given
89	        // method. If there are, we can call this method binding callback immediately.
90	        $method = static::normalizeMethod($callback);
91	
92	        if ($container->hasMethodBinding($method)) {
93	            return $container->callMethodBinding($method, $callback[0]);
94	        }
95	
96	        return Util::unwrapIfClosure($default);
97	    }
98	
99	    /**
100	     * Normalize the given callback into a Class@method string.
101	     *
102	     * @param  callable  $callback
103	     * @return string
104	     */
105	    protected static function normalizeMethod($callback)
106	    {
107	        $class = is_string($callback[0]) ? $callback[0] : get_class($callback[0]);
108	
109	        return "{$class}@{$callback[1]}";
110	    }
111	
112	    /**
113	     * Get all dependencies for a given method.
114	     *
115	     * @param  \Illuminate\Container\Container  $container
116	     * @param  callable|string  $callback
117	     * @param  array  $parameters
118	     * @return array
119	     *
120	     * @throws \ReflectionException
121	     */
122	    protected static function getMethodDependencies($container, $callback, array $parameters = [])
123	    {
124	        $dependencies = [];
125	
126	        foreach (static::getCallReflector($callback)->getParameters() as $parameter) {
127	            static::addDependencyForCallParameter($container, $parameter, $parameters, $dependencies);
128	        }
129	
130	        return array_merge($dependencies, array_values($parameters));
131	    }
132	
133	    /**
134	     * Get the proper reflection instance for the given callback.
135	     *
136	     * @param  callable|string  $callback
137	     * @return \ReflectionFunctionAbstract
138	     *
139	     * @throws \ReflectionException
140	     */
141	    protected static function getCallReflector($callback)
142	    {
143	        if (is_string($callback) && str_contains($callback, '::')) {
144	            $callback = explode('::', $callback);
145	        } elseif (is_object($callback) && ! $callback instanceof Closure) {
146	            $callback = [$callback, '__invoke'];
147	        }
148	
149	        return is_array($callback)
150	            ? new ReflectionMethod($callback[0], $callback[1])
151	            : new ReflectionFunction($callback);
152	    }
153	
154	    /**
155	     * Get the dependency for the given call parameter.
156	     *
157	     * @param  \Illuminate\Container\Container  $container
158	     * @param  \ReflectionParameter  $parameter
159	     * @param  array  $parameters
160	     * @param  array  $dependencies
161	     * @return void
162	     *
163	     * @throws \Illuminate\Contracts\Container\BindingResolutionException
164	     */
165	    protected static function addDependencyForCallParameter(
166	        $container,
167	        $parameter,
168	        array &$parameters,
169	        &$dependencies,
170	    ) {
171	        $pendingDependencies = [];
172	
173	        if (array_key_exists($paramName = $parameter->getName(), $parameters)) {
174	            $pendingDependencies[] = $parameters[$paramName];
175	
176	            unset($parameters[$paramName]);
177	        } elseif ($attribute = Util::getContextualAttributeFromDependency($parameter)) {
178	            $pendingDependencies[] = $container->resolveFromAttribute($attribute, $parameter);
179	        } elseif (! is_null($className = Util::getParameterClassName($parameter))) {
180	            if (array_key_exists($className, $parameters)) {
181	                $pendingDependencies[] = $parameters[$className];
182	
183	                unset($parameters[$className]);
184	            } elseif ($parameter->isVariadic()) {
185	                $variadicDependencies = $container->make($className);
186	
187	                $pendingDependencies = array_merge($pendingDependencies, is_array($variadicDependencies)
188	                    ? $variadicDependencies
189	                    : [$variadicDependencies]);
190	            } elseif ($parameter->isDefaultValueAvailable() && ! $container->bound($className)) {
191	                $pendingDependencies[] = $parameter->getDefaultValue();
192	            } else {
193	                $pendingDependencies[] = $container->make($className);
194	            }
195	        } elseif ($parameter->isDefaultValueAvailable()) {
196	            $pendingDependencies[] = $parameter->getDefaultValue();
197	        } elseif (! $parameter->isOptional() && ! array_key_exists($paramName, $parameters)) {
198	            $message = "Unable to resolve dependency [{$parameter}] in class {$parameter->getDeclaringClass()->getName()}";
199	
200	            throw new BindingResolutionException($message);
201	        }
202	
203	        foreach ($pendingDependencies as $dependency) {
204	            $container->fireAfterResolvingAttributeCallbacks($parameter->getAttributes(), $dependency);
205	        }
206	
207	        $dependencies = array_merge($dependencies, $pendingDependencies);
208	    }
209	
210	    /**
211	     * Determine if the given string is in Class@method syntax.
212	     *
213	     * @param  mixed  $callback
214	     * @return bool
215	     */
216	    protected static function isCallableWithAtSign($callback)
217	    {
218	        return is_string($callback) && str_contains($callback, '@');
219	    }
220	}
