3	namespace Illuminate\Container;
4	
5	use Closure;
6	use Illuminate\Contracts\Container\ContextualAttribute;
7	use ReflectionAttribute;
8	use ReflectionNamedType;
9	
10	/**
11	 * @internal
12	 */
13	class Util
14	{
15	    /**
16	     * If the given value is not an array and not null, wrap it in one.
17	     *
18	     * From Arr::wrap() in Illuminate\Support.
19	     *
20	     * @param  mixed  $value
21	     * @return array
22	     */
23	    public static function arrayWrap($value)
24	    {
25	        if (is_null($value)) {
26	            return [];
27	        }
28	
29	        return is_array($value) ? $value : [$value];
30	    }
31	
32	    /**
33	     * Return the default value of the given value.
34	     *
35	     * From global value() helper in Illuminate\Support.
36	     *
37	     * @param  mixed  $value
38	     * @param  mixed  ...$args
39	     * @return mixed
40	     */
41	    public static function unwrapIfClosure($value, ...$args)
42	    {
43	        return $value instanceof Closure ? $value(...$args) : $value;
44	    }
45	
46	    /**
47	     * Get the class name of the given parameter's type, if possible.
48	     *
49	     * From Reflector::getParameterClassName() in Illuminate\Support.
50	     *
51	     * @param  \ReflectionParameter  $parameter
52	     * @return string|null
53	     */
54	    public static function getParameterClassName($parameter)
55	    {
56	        $type = $parameter->getType();
57	
58	        if (! $type instanceof ReflectionNamedType || $type->isBuiltin()) {
59	            return null;
60	        }
61	
62	        $name = $type->getName();
63	
64	        if (! is_null($class = $parameter->getDeclaringClass())) {
65	            if ($name === 'self') {
66	                return $class->getName();
67	            }
68	
69	            if ($name === 'parent' && $parent = $class->getParentClass()) {
70	                return $parent->getName();
71	            }
72	        }
73	
74	        return $name;
75	    }
76	
77	    /**
78	     * Get a contextual attribute from a dependency.
79	     *
80	     * @param  \ReflectionParameter  $dependency
81	     * @return \ReflectionAttribute|null
82	     */
83	    public static function getContextualAttributeFromDependency($dependency)
84	    {
85	        return $dependency->getAttributes(ContextualAttribute::class, ReflectionAttribute::IS_INSTANCEOF)[0] ?? null;
86	    }
87	}
